import type { JSX } from "solid-js"

type IconProps = { size?: number; class?: string }
type IllustrationProps = { width?: number; height?: number; class?: string }

function mk(viewBox: string, inner: string, defaultSize: number) {
  return function Icon(props: IconProps): JSX.Element {
    return (
      <svg
        viewBox={viewBox}
        width={props.size ?? defaultSize}
        height={props.size ?? defaultSize}
        fill="none"
        aria-hidden="true"
        class={props.class}
        style={{ "flex-shrink": "0", display: "inline-block" }}
        innerHTML={inner}
      />
    )
  }
}

function mkIllustration(viewBox: string, inner: string, dw: number, dh: number) {
  return function Illustration(props: IllustrationProps): JSX.Element {
    return (
      <svg
        viewBox={viewBox}
        width={props.width ?? dw}
        height={props.height ?? dh}
        fill="none"
        aria-hidden="true"
        class={props.class}
        innerHTML={inner}
      />
    )
  }
}

